def smallest_change(arr):
    """
    Given an array arr of integers, find the minimum number of elements that
    need to be changed to make the array palindromic. A palindromic array is an array that
    is read the same backwards and forwards. In one change, you can change one element to any other element.

    For example:
    smallest_change([1,2,3,5,4,7,9,6]) == 4
    smallest_change([1, 2, 3, 4, 3, 2, 2]) == 1
    smallest_change([1, 2, 3, 2, 1]) == 0
    """

    # O(n)
    def is_palindromic(s):
        # O(n)
        for i in range(int(len(s) / 2)):
            if s[i] != s[len(s) - i - 1]:
                return False
        return True

    # O(n)
    def find_min_change(s):
        # O(n)
        for i in range(int(len(s) / 2)):
            # O(n)
            for c in "123456789":
                # O(n)
                new_arr = [c if j == i else x for j, x in enumerate(s)]
                # O(n)
                if is_palindromic("".join(new_arr)):
                    return new_arr

    # O(n)
    def find_min_change_helper(s, arr):
        # O(n)
        for i in range(int(len(s) / 2)):
            # O(n)
            for c in "123456789":
                # O(n)
                new_arr = [c if j == i else x for j, x in enumerate(s)]
                # O(n)
                if new_arr not in arr:
                    new_arr_min = find_min_change(new_arr)
                    if new_arr_min:
                        # O(n)
                        for i in new_arr_min:
                            new_arr.append(i)
                        # O(n)
                        for i in new_arr:
                            arr.append(i)
                        # O(n)

