def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """

    # #1 Best Practices Solution by Amit
    import string
    res = []
    for i in s:
        if i in string.ascii_letters:
            res.append(i.upper() if i.islower() else i.lower())
        else:
            res.append(i)
    return "".join(res)

def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """

    # Solution
    result = []

    for i in s:
        if (i >= 'a' and i <= 'z') or (i >= 'A' and i <= 'Z'):
            # swap the case
            if i >= 'a' and i <= 'z':
                # lower -> upper
                result.append(chr(ord(i) - ord('a') + ord('A')))
            else:
                # upper -> lower
                result.append(chr(ord(i) - ord('A') + ord('a')))
        else:
            # don't swap the case
            result.append(i)

    return ''.join(result[::-1])
